import React from "react";

/* "corporativo." logo — embedded as data URIs so the component is fully
   self-contained wherever the bundle is consumed. Source artwork:
   assets/corporativo-logo*.png (999×175; mark crop 246×129). */
const LOGO_SRC = {
  positive: "data:image/png;base64,",
  negative: "data:image/png;base64,",
  white: "data:image/png;base64,",
};
const MARK_SRC = "data:image/png;base64,";

/**
 * Corporativo logo — the full "corporativo." wordmark (orange infinity "co"
 * ligature + gray lettering + orange period). Use variant "negative" on dark
 * surfaces and "white" on orange/colored surfaces. markOnly renders just the
 * infinity mark (favicon / app-icon sizes only).
 */
export function Logo({ variant = "positive", height = 32, markOnly = false, showName, style = {} }) {
  if (showName === false) markOnly = true; // legacy QPH API compat
  if (markOnly) {
    return (
      <img
        src={MARK_SRC}
        alt="corporativo"
        style={{ height, width: "auto", display: "inline-block", ...style }}
      />
    );
  }
  const src = LOGO_SRC[variant] || LOGO_SRC.positive;
  return (
    <img
      src={src}
      alt="corporativo."
      style={{ height, width: "auto", display: "inline-block", ...style }}
    />
  );
}
